// Process each property and find interested customers
const properties = $json;
const results = [];

for (const property of properties) {
  // In a real implementation, you would query a customer_preferences or saved_searches table
  // For now, we'll simulate finding interested customers based on property type/price range

  const interestedCustomers = [
    { id: 1, name: 'John Doe', email: 'john@example.com', phone: '+1234567890', preferences: { type: property.property_type, maxPrice: 500000 } },
    { id: 2, name: 'Jane Smith', email: 'jane@example.com', phone: '+1234567891', preferences: { type: property.property_type, minBeds: 3 } }
  ].filter(c => {
    // Simple matching logic - in reality this would be more sophisticated
    const matchesType = !c.preferences.type || c.preferences.type === property.property_type;
    const matchesPrice = !c.preferences.maxPrice || property.price <= c.preferences.maxPrice;
    const matchesBeds = !c.preferences.minBeds || property.bedrooms >= c.preferences.minBeds;
    return matchesType && matchesPrice && matchesBeds;
  });

  for (const customer of interestedCustomers) {
    results.push({
      json: {
        propertyId: property.id,
        propertyTitle: property.title,
        propertyPrice: property.price,
        propertyAddress: property.address,
        customerId: customer.id,
        customerName: customer.name,
        customerEmail: customer.email,
        customerPhone: customer.phone,
        agentName: property.agent_first_name && property.agent_last_name ? `${property.agent_first_name} ${property.agent_last_name}` : 'Unassigned',
        updateType: property.updated_at > new Date(Date.now() - 15 * 60 * 1000) ? 'new' : 'updated', // New if updated in last 15 min
        timestamp: new Date().toISOString()
      }
    });
  }
}

return results;

// Send email notification
return [{ json: {
  notificationId: 'email_' + $json["propertyId"] + '_' + $json["customerId"],
  type: 'email',
  to: $json["customerEmail"],
  subject: `New Property Match: ${$json["propertyTitle"]}`,
  body: `Hello ${$json["customerName"]},

We have a new property that matches your criteria:

Title: ${$json["propertyTitle"]}
Price: $${$json["propertyPrice"].toLocaleString()}
Address: ${$json["propertyAddress"]}
Agent: ${$json["agentName"]}

View details: http://your-crm-domain.com/properties/${$json["propertyId"]}

Best regards,
Your Real Estate Team`,
  status: 'sent',
  timestamp: new Date().toISOString()
} }];

// Send SMS notification (if phone available and opt-in)
if (!$json["customerPhone"]) {
  return []; // Skip if no phone
}

return [{ json: {
  notificationId: 'sms_' + $json["propertyId"] + '_' + $json["customerId"],
  type: 'sms',
  to: $json["customerPhone"],
  message: `New ${$json["propertyType"]||'property'}: ${$json["propertyTitle"]} - $$${$json["propertyPrice"].toLocaleString()}. Reply STOP to opt-out.`,
  status: 'sent',
  timestamp: new Date().toISOString()
} }];
